module decoder_2to4(
    input [1:0] inverted_din,

    output reg [3:0] dout
);
    always @(*) begin
        case (inverted_din)
            2'b00: dout = 4'b0001;
            2'b01: dout = 4'b0010;
            2'b10: dout = 4'b0100;
            2'b11: dout = 4'b1000;
            default: dout = 4'b0000;
        endcase
    end
endmodule
